<script setup lang="ts">
import { computed, inject, ref, watch, type Ref } from 'vue';
import { useLocalStorage } from '@vueuse/core';
import ViewModeToggle from '../components/ViewModeToggle.vue';
import { findMatchingMagicalGirl } from '../magicalGirlControl';
import { useDataStore } from '../store';

type ViewMode = 'compact' | 'detail';
type TabId = 'present' | 'girls' | 'raven';

const store = useDataStore();
const viewToggleRef = ref<InstanceType<typeof ViewModeToggle> | null>(null);
const expandedKeys = ref(new Set<string>());
const viewMode = useLocalStorage<ViewMode>('msp_v4:present_view_mode', 'compact');

// 注入切换方法
const switchToTab = inject<(tabId: TabId, options?: { selectGirl?: string }) => void>('switchToTab');

const EMOTION_LEVEL_WEIGHT = {
  极端: 4,
  强烈: 3,
  普通: 2,
  些许: 1,
  微弱: 0,
} as const;

function getEmotionToneClass(level: string) {
  switch (level) {
    case '微弱':
      return 'tag-faint';
    case '些许':
      return 'tag-light';
    case '普通':
      return 'tag-normal';
    case '强烈':
      return 'tag-strong';
    case '极端':
      return 'tag-extreme';
    default:
      return 'tag-faint';
  }
}

function getLustToneClass(lust: number) {
  if (lust >= 85) return 'lust-overflow';
  if (lust >= 65) return 'lust-burning';
  if (lust >= 40) return 'lust-warm';
  if (lust >= 15) return 'lust-awake';
  return 'lust-calm';
}

type EmotionLevel = keyof typeof EMOTION_LEVEL_WEIGHT;
type PresentCharacter = {
  名称: string;
  是否变身: boolean;
  感情: Record<string, EmotionLevel>;
  心声: string;
  情欲: number;
};

const characters = computed(() =>
  (Object.entries(store.data.在场角色 ?? {}) as Array<[string, PresentCharacter]>)
    .map(([key, value]) => {
      const displayName = (value.名称 || key).trim() || key;
      const mgMatch = findMatchingMagicalGirl(displayName, store.data.魔法少女 ?? {});

      return {
        key,
        displayName,
        transformed: value.是否变身,
        lust: value.情欲,
        lustClass: getLustToneClass(value.情欲),
        thought: value.心声,
        emotions: Object.entries(value.感情 ?? {})
          .map(([name, level]) => ({
            name,
            level,
            toneClass: getEmotionToneClass(level),
            weight: EMOTION_LEVEL_WEIGHT[level] ?? -1,
          }))
          .sort((left, right) => right.weight - left.weight || left.name.localeCompare(right.name, 'zh-Hans-CN')),
        isMagicalGirl: mgMatch !== null,
        magicalGirlKey: mgMatch?.key ?? null,
      };
    })
    .sort((left, right) => left.displayName.localeCompare(right.displayName, 'zh-Hans-CN')),
);

function handleViewModeChange(mode: ViewMode) {
  viewMode.value = mode;
  expandedKeys.value.clear();
}

function toggleExpand(key: string) {
  if (expandedKeys.value.has(key)) {
    expandedKeys.value.delete(key);
  } else {
    expandedKeys.value.add(key);
  }
}

function jumpToMagicalGirl(key: string) {
  // 使用注入的切换方法，无需刷新页面
  switchToTab?.('girls', { selectGirl: key });
}

// 清理过期的展开状态
watch(
  () => characters.value.map(c => c.key),
  keys => {
    const validKeys = new Set(keys);
    expandedKeys.value.forEach(k => {
      if (!validKeys.has(k)) {
        expandedKeys.value.delete(k);
      }
    });
  },
);
</script>

