<template>
  <div class="shell">
    <header class="top">
      <div class="header-row">
        <div class="location-card">
          <div class="location-head">
            <div class="eyebrow">当前地点</div>
            <div class="location-inline">{{ locationSummary }}</div>
          </div>
        </div>
        <ThemeToggle />
      </div>
    </header>

    <div class="sticky-wrapper">
      <GlobalManaBar class="sticky-mana" />
    </div>

    <FallRequestPanel />

    <TabNav v-model="activeTab" :tabs="tabs" />

    <main class="content">
      <PresentCharactersPage v-if="activeTab === 'present'" />
      <MagicalGirlListPage v-else-if="activeTab === 'girls'" />
      <RavenPage v-else-if="activeTab === 'raven'" />
    </main>
  </div>
</template>

<script setup lang="ts">
import { computed, nextTick, provide, watchEffect } from 'vue';
import { useLocalStorage } from '@vueuse/core';
import FallRequestPanel from './components/FallRequestPanel.vue';
import GlobalManaBar from './components/GlobalManaBar.vue';
import TabNav from './components/TabNav.vue';
import ThemeToggle from './components/ThemeToggle.vue';
import MagicalGirlListPage from './pages/MagicalGirlListPage.vue';
import PresentCharactersPage from './pages/PresentCharactersPage.vue';
import RavenPage from './pages/RavenPage.vue';
import { useDataStore } from './store';

const store = useDataStore();

const tabs: { id: string; label: string }[] = [
  { id: 'present', label: '在场角色' },
  { id: 'girls', label: '魔法少女' },
  { id: 'raven', label: '渡鸦' },
];

type TabId = 'present' | 'girls' | 'raven';

const activeTab = useLocalStorage<TabId>('msp_v4:status_bar:tab', 'present');

// 用于跨组件通信的事件
const selectGirlEvent = ref<string | null>(null);

watchEffect(() => {
  if (!tabs.some(tab => tab.id === activeTab.value)) {
    activeTab.value = 'present';
  }
});

// 提供给子组件的切换方法
function switchToTab(tabId: TabId, options?: { selectGirl?: string }) {
  activeTab.value = tabId;
  if (options?.selectGirl) {
    // 通过 ref 传递选中事件
    nextTick(() => {
      selectGirlEvent.value = options.selectGirl!;
      // 清空事件，允许下次触发
      setTimeout(() => {
        selectGirlEvent.value = null;
      }, 100);
    });
  }
}

// 提供给子组件使用
provide('switchToTab', switchToTab);
provide('selectGirlEvent', selectGirlEvent);

const location = computed(() => {
  const value = store.data.地点 as { 城市?: string; 地区?: string; 地址?: string } | undefined;
  return {
    城市: value?.城市?.trim() || '新都',
    地区: value?.地区?.trim() || '未知地区',
    地址: value?.地址?.trim() || '未知地点',
  };
});

const locationSummary = computed(() =>
  [...new Set([location.value.城市, location.value.地区, location.value.地址].filter(Boolean))].join(' · '),
);
</script>

