<template>
  <button
    class="theme-toggle"
    type="button"
    :title="isDark ? '切换到日间模式' : '切换到夜间模式'"
    :aria-label="isDark ? '切换到日间模式' : '切换到夜间模式'"
    @click="toggleTheme"
  >
    <Transition name="theme-icon" mode="out-in">
      <svg v-if="isDark" key="moon" class="icon" viewBox="0 0 24 24" aria-hidden="true">
        <path
          d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"
          fill="currentColor"
          stroke="currentColor"
          stroke-width="1.5"
          stroke-linecap="round"
          stroke-linejoin="round"
        />
      </svg>
      <svg v-else key="sun" class="icon" viewBox="0 0 24 24" aria-hidden="true">
        <circle cx="12" cy="12" r="4" fill="currentColor" />
        <path
          d="M12 2v2M12 20v2M4.93 4.93l1.41 1.41M17.66 17.66l1.41 1.41M2 12h2M20 12h2M6.34 17.66l-1.41 1.41M19.07 4.93l-1.41 1.41"
          stroke="currentColor"
          stroke-width="2"
          stroke-linecap="round"
        />
      </svg>
    </Transition>
  </button>
</template>

<script setup lang="ts">
import { usePreferredDark } from '@vueuse/core';

type Theme = 'light' | 'dark';

const preferredDark = usePreferredDark();
const storedTheme = useLocalStorage<Theme>('msp_v4:theme', 'dark');

// 初始化时，如果用户没有手动选择过主题，则跟随系统
const isDark = computed({
  get: () => storedTheme.value === 'dark',
  set: (value: boolean) => {
    storedTheme.value = value ? 'dark' : 'light';
  },
});

// 应用主题到根元素
function applyTheme(theme: Theme) {
  document.documentElement.setAttribute('data-theme', theme);
}

// 监听主题变化
watchEffect(() => {
  applyTheme(storedTheme.value);
});

// 监听系统主题变化（仅当用户未手动选择时）
watch(preferredDark, (newVal) => {
  // 可选：取消注释以下代码以启用自动跟随系统主题
  // if (!localStorage.getItem('msp_v4:theme')) {
  //   storedTheme.value = newVal ? 'dark' : 'light';
  // }
});

function toggleTheme() {
  isDark.value = !isDark.value;
}

// 初始应用
onMounted(() => {
  applyTheme(storedTheme.value);
});
</script>

<style scoped>
.theme-toggle {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--c-border);
  background: var(--c-panel-glass);
  color: var(--c-ink);
  cursor: pointer;
  transition:
    background var(--duration-fast) ease,
    border-color var(--duration-fast) ease,
    color var(--duration-fast) ease,
    transform var(--duration-fast) ease;
}

.theme-toggle:hover {
  background: var(--c-accent-soft);
  border-color: var(--c-accent);
  color: var(--c-accent-strong);
  transform: scale(1.05);
}

.theme-toggle:active {
  transform: scale(0.95);
}

.theme-toggle:focus-visible {
  outline: 2px solid var(--c-accent);
  outline-offset: 2px;
}

.icon {
  width: 20px;
  height: 20px;
}

/* 图标切换动画 */
.theme-icon-enter-active,
.theme-icon-leave-active {
  transition: opacity var(--duration-fast) ease, transform var(--duration-fast) ease;
}

.theme-icon-enter-from {
  opacity: 0;
  transform: rotate(-90deg) scale(0.5);
}

.theme-icon-leave-to {
  opacity: 0;
  transform: rotate(90deg) scale(0.5);
}
</style>
