<template>
  <div class="view-toggle">
    <button
      class="toggle-btn"
      :class="{ active: mode === 'compact' }"
      type="button"
      title="紧凑视图"
      aria-label="紧凑视图"
      @click="setMode('compact')"
    >
      <svg viewBox="0 0 24 24" aria-hidden="true">
        <rect x="3" y="3" width="18" height="6" rx="1" fill="currentColor" />
        <rect x="3" y="11" width="18" height="6" rx="1" fill="currentColor" opacity="0.6" />
        <rect x="3" y="19" width="18" height="4" rx="1" fill="currentColor" opacity="0.3" />
      </svg>
    </button>
    <button
      class="toggle-btn"
      :class="{ active: mode === 'detail' }"
      type="button"
      title="详细视图"
      aria-label="详细视图"
      @click="setMode('detail')"
    >
      <svg viewBox="0 0 24 24" aria-hidden="true">
        <rect x="3" y="3" width="18" height="18" rx="2" fill="currentColor" opacity="0.2" />
        <rect x="5" y="5" width="14" height="4" rx="1" fill="currentColor" />
        <rect x="5" y="11" width="14" height="4" rx="1" fill="currentColor" opacity="0.7" />
        <rect x="5" y="17" width="8" height="2" rx="0.5" fill="currentColor" opacity="0.4" />
      </svg>
    </button>
  </div>
</template>

<script setup lang="ts">
import { useLocalStorage } from '@vueuse/core';

type ViewMode = 'compact' | 'detail';

const props = defineProps<{
  itemCount?: number;
  threshold?: number;
}>();

const emit = defineEmits<{
  change: [mode: ViewMode];
}>();

const storedMode = useLocalStorage<ViewMode>('msp_v4:view_mode', 'compact');

const threshold = computed(() => props.threshold ?? 5);

// 计算实际使用的模式（考虑自动判断）
const mode = computed<ViewMode>(() => {
  // 如果用户手动选择了模式，则尊重用户选择
  // 否则根据数量自动判断
  const count = props.itemCount ?? 0;
  if (count > threshold.value) {
    return 'compact';
  }
  return storedMode.value;
});

function setMode(newMode: ViewMode) {
  storedMode.value = newMode;
  emit('change', newMode);
}

// 暴露当前模式供外部使用
defineExpose({
  mode,
  setMode,
});
</script>

