<template>
  <section v-if="requests.length" class="panel">
    <div class="head">
      <div>
        <div class="title">精神极限警示</div>
        <div class="subtitle">到达精神极限后，是否反转只由玩家决定</div>
      </div>
      <div class="count">待处理 {{ requests.length }}</div>
    </div>

    <div class="list">
      <article v-for="item in requests" :key="item.key" class="item">
        <div class="top-row">
          <div class="identity">
            <div class="name">{{ item.magicName }}</div>
            <div class="sub">真名：{{ item.trueName }}</div>
          </div>
          <div class="badge-group">
            <div class="badge type">{{ item.typeLabel }}</div>
            <div class="badge">精神已达极限</div>
          </div>
        </div>

        <div class="reason">{{ item.magicName }} 的精神已达极限，真的要让她反转吗？</div>

        <template v-if="editingKey === item.key && !item.protected">
          <label class="field">
            <span class="field-label">新的堕落魔法名</span>
            <input v-model="editingMagicName" class="input" type="text" placeholder="输入切换后的当前魔法名" />
          </label>
          <div class="hint">动态角色没有世界书纠错，所以确认反转时需要同时填写新的当前魔法名。</div>

          <div class="actions">
            <button class="btn danger" type="button" :disabled="!editingMagicName.trim()" @click="confirmDynamic(item.key)">
              保存并反转
            </button>
            <button class="btn" type="button" @click="cancelDynamicEdit">取消</button>
          </div>
        </template>

        <div v-else class="actions">
          <button class="btn danger" type="button" @click="confirm(item.key)">
            {{ item.protected ? '是，确认反转' : '填写魔法名并反转' }}
          </button>
          <button class="btn" type="button" @click="dismiss(item.key)">否，保持常态</button>
        </div>
      </article>
    </div>
  </section>
</template>

<script setup lang="ts">
import {
  confirmFall,
  dismissFallRequest,
  getCurrentMagicName,
  getMagicalGirlTypeLabel,
  getVisibleTrueName,
  loadPreloadedMagicGirlCatalog,
  resolvePreloadedMagicGirl,
  switchDynamicGirlState,
  type PreloadedMagicGirlCatalog,
} from '../magicalGirlControl';
import { useDataStore } from '../store';

const store = useDataStore();

const catalog = ref<PreloadedMagicGirlCatalog>({
  worldbookName: null,
  byTrueName: {},
  byAlias: {},
});

const editingKey = ref('');
const editingMagicName = ref('');

async function refreshCatalog() {
  catalog.value = await loadPreloadedMagicGirlCatalog();
}

onMounted(() => {
  refreshCatalog();
});

const requests = computed(() =>
  Object.entries(store.data.魔法少女 ?? {})
    .filter(([, girl]) => girl.精神极限)
    .sort(([left], [right]) => left.localeCompare(right, 'zh-Hans-CN'))
    .map(([key, girl]) => ({
      key,
      magicName: getCurrentMagicName(girl),
      trueName: getVisibleTrueName(girl),
      protected: Boolean(resolvePreloadedMagicGirl(catalog.value, key, girl)),
      typeLabel: getMagicalGirlTypeLabel(girl),
    })),
);

watchEffect(() => {
  if (!editingKey.value) {
    return;
  }

  if (!requests.value.some(item => item.key === editingKey.value)) {
    cancelDynamicEdit();
  }
});

function confirm(key: string) {
  const girl = store.data.魔法少女[key];
  if (!girl) {
    return;
  }

  const isProtected = Boolean(resolvePreloadedMagicGirl(catalog.value, key, girl));
  if (isProtected) {
    confirmFall(girl);
    return;
  }

  editingKey.value = key;
  editingMagicName.value = girl.魔法名;
}

function confirmDynamic(key: string) {
  const girl = store.data.魔法少女[key];
  if (!girl) {
    return;
  }

  const saved = switchDynamicGirlState(girl, true, editingMagicName.value);
  if (!saved) {
    return;
  }

  cancelDynamicEdit();
}

function cancelDynamicEdit() {
  editingKey.value = '';
  editingMagicName.value = '';
}

function dismiss(key: string) {
  const girl = store.data.魔法少女[key];
  if (!girl) {
    return;
  }

  dismissFallRequest(girl);
  if (editingKey.value === key) {
    cancelDynamicEdit();
  }
}
</script>

