<script setup lang="ts">
import { computed, inject, onMounted, ref, watch, type Ref } from 'vue';
import { useLocalStorage } from '@vueuse/core';
import {
  getCurrentMagicName,
  getMagicPercent,
  getMagicalGirlTypeLabel,
  getVisibleTrueName,
  isMagicalGirlPresent,
  loadPreloadedMagicGirlCatalog,
  resolvePreloadedMagicGirl,
  switchDynamicGirlState,
  type MagicalGirlRecord,
  type PreloadedMagicGirlCatalog,
} from '../magicalGirlControl';
import { getManaStageClass, getManaStateLabel, type ManaStageClass } from '../manaStage';
import { useDataStore } from '../store';
import ViewModeToggle from '../components/ViewModeToggle.vue';

type ViewMode = 'compact' | 'detail';

type KnotView = {
  name: string;
  desc: string;
};

type AttitudeToneClass =
  | 'stranger'
  | 'detached'
  | 'neutral'
  | 'trust'
  | 'love'
  | 'dislike'
  | 'hostile'
  | 'conflicted';

type GirlView = {
  key: string;
  magicName: string;
  trueName: string;
  fallen: boolean;
  mentalBreak: boolean;
  protected: boolean;
  typeLabel: string;
  toneClass: 'normal' | 'fallen';
  magicCurrent: number;
  magicMax: number;
  magicPercent: number;
  manaStageClass: ManaStageClass;
  manaStateLabel: string;
  attitude: string;
  attitudeToneClass: AttitudeToneClass;
  unresolvedKnots: KnotView[];
  resolvedKnots: KnotView[];
  isPresent: boolean;
};

const store = useDataStore();

const catalog = ref<PreloadedMagicGirlCatalog>({
  worldbookName: null,
  byTrueName: {},
  byAlias: {},
});

const selectedGirlKey = ref('');
const switchDialogOpen = ref(false);
const switchTargetKey = ref('');
const switchNextFallen = ref(false);
const switchMagicName = ref('');
const deleteTargetKey = ref('');
const viewToggleRef = ref<InstanceType<typeof ViewModeToggle> | null>(null);
const viewMode = useLocalStorage<ViewMode>('msp_v4:girls_view_mode', 'compact');

// 注入选中事件
const selectGirlEvent = inject<Ref<string | null>>('selectGirlEvent');

async function refreshCatalog() {
  catalog.value = await loadPreloadedMagicGirlCatalog();
}

onMounted(() => {
  refreshCatalog();
});

// 监听选中事件，自动选中对应的魔法少女
watch(selectGirlEvent, (newKey) => {
  if (newKey) {
    selectedGirlKey.value = newKey;
  }
});

function sortByChinese<T extends { name: string }>(items: T[]) {
  return items.sort((left, right) => left.name.localeCompare(right.name, 'zh-Hans-CN'));
}

function getAttitudeToneClass(attitude: string): AttitudeToneClass {
  switch (attitude) {
    case '陌生':
      return 'stranger';
    case '无关心':
      return 'detached';
    case '一般':
      return 'neutral';
    case '信任':
      return 'trust';
    case '恋心':
      return 'love';
    case '讨厌':
      return 'dislike';
    case '死仇':
      return 'hostile';
    case '爱恨交织':
      return 'conflicted';
    default:
      return 'neutral';
  }
}

function buildKnotGroups(girl: MagicalGirlRecord) {
  const knots = sortByChinese(
    Object.entries(girl.心结 ?? {}).map(([name, knot]) => ({
      name,
      desc: knot.描述 || '???',
      resolved: knot.是否解开,
    })),
  );

  return {
    unresolvedKnots: knots.filter(knot => !knot.resolved).map(({ name, desc }) => ({ name, desc })),
    resolvedKnots: knots.filter(knot => knot.resolved).map(({ name }) => ({ name, desc: '' })),
  };
}

const girls = computed<GirlView[]>(() =>
  (Object.entries(store.data.魔法少女 ?? {}) as Array<[string, MagicalGirlRecord]>)
    .map(([key, girl]) => {
      const meta = resolvePreloadedMagicGirl(catalog.value, key, girl);
      const magicPercent = getMagicPercent(girl.魔力, girl.魔力上限);
      const toneClass = girl.是否堕落 ? 'fallen' : 'normal';
      const manaStageClass = getManaStageClass(magicPercent);
      const { unresolvedKnots, resolvedKnots } = buildKnotGroups(girl);
      const present = isMagicalGirlPresent(key, girl, store.data.在场角色 ?? {});

      return {
        key,
        magicName: getCurrentMagicName(girl),
        trueName: getVisibleTrueName(girl),
        fallen: girl.是否堕落,
        mentalBreak: girl.精神极限,
        protected: Boolean(meta),
        typeLabel: getMagicalGirlTypeLabel(girl),
        toneClass,
        magicCurrent: girl.魔力,
        magicMax: girl.魔力上限,
        magicPercent,
        manaStageClass,
        manaStateLabel: getManaStateLabel(magicPercent),
        attitude: girl.对主角的态度,
        attitudeToneClass: getAttitudeToneClass(girl.对主角的态度),
        unresolvedKnots,
        resolvedKnots,
        isPresent: present,
      };
    })
    .sort((left, right) => left.magicName.localeCompare(right.magicName, 'zh-Hans-CN')),
);

const selectedGirl = computed(() => girls.value.find(item => item.key === selectedGirlKey.value) ?? null);
const switchTargetItem = computed(() => girls.value.find(item => item.key === switchTargetKey.value) ?? null);
const deleteTargetItem = computed(() => girls.value.find(item => item.key === deleteTargetKey.value) ?? null);

watchEffect(() => {
  if (selectedGirlKey.value && !selectedGirl.value) {
    selectedGirlKey.value = '';
  }
});

function selectGirl(key: string) {
  selectedGirlKey.value = key;
}

function clearSelection() {
  selectedGirlKey.value = '';
}

function handleViewModeChange(mode: ViewMode) {
  viewMode.value = mode;
}

function openSwitchDialog(key: string) {
  const item = girls.value.find(girl => girl.key === key);
  if (!item || item.protected) {
    return;
  }

  switchTargetKey.value = key;
  switchNextFallen.value = !item.fallen;
  switchMagicName.value = item.magicName;
  switchDialogOpen.value = true;
}

function closeSwitchDialog() {
  switchDialogOpen.value = false;
  switchTargetKey.value = '';
  switchMagicName.value = '';
  switchNextFallen.value = false;
}

function confirmSwitch() {
  const key = switchTargetKey.value;
  if (!key) {
    return;
  }

  const girl = store.data.魔法少女[key];
  if (!girl) {
    return;
  }

  const saved = switchDynamicGirlState(girl, switchNextFallen.value, switchMagicName.value);
  if (!saved) {
    return;
  }

  closeSwitchDialog();
}

function openDeleteDialog(key: string) {
  const item = girls.value.find(girl => girl.key === key);
  if (!item || item.protected) {
    return;
  }

  deleteTargetKey.value = key;
}

function closeDeleteDialog() {
  deleteTargetKey.value = '';
}

function confirmDelete() {
  const key = deleteTargetKey.value;
  if (!key) {
    return;
  }

  delete (store.data.魔法少女 as Record<string, unknown>)[key];
  if (selectedGirlKey.value === key) {
    clearSelection();
  }
  closeDeleteDialog();
}
</script>

